SELECT access_id, material_id, user_id, access_date, access_type, access_duration, access_ip
FROM access_logs
WHERE material_id = 1;

SELECT material_name
FROM materials
WHERE material_id = 1;

SELECT updated_at, updated_by
FROM material_history
WHERE material_id = 0 AND version = 2;

SELECT AVG(density) AS average_density 
FROM material_properties 
WHERE material_id IN (SELECT material_id FROM materials WHERE material_name LIKE '%Aluminum%');

SELECT material_name, manufacturer
FROM materials
WHERE updated_at = (SELECT MAX(updated_at) FROM materials);

SELECT COUNT(*) 
FROM material_usage 
WHERE material_id = 0;

SELECT COUNT(DISTINCT material_id) 
FROM material_variants 
WHERE variant_name LIKE '%O%';

SELECT COUNT(*)
FROM material_documents
WHERE doc_path LIKE 'documents/%';

SELECT SUM(quantity) 
FROM material_usage 
WHERE material_id = (SELECT material_id FROM materials WHERE material_name = 'Aluminum Alloy 6061');
